local function SavePlayerGameData(player, immediate)
    if AIManager:isAI(player.rakssid) then
        return
    end
    local data = {}
    data.level = player.level
    data.money = player.money
    data.cur_exp = player.cur_exp
    data.yaoshi = player.yaoshi
    data.expDoubleTime = player.expDoubleTime
    data.privilegeCard = player.privilegeCard
    data.equip_dress = player.equip_dress
    data.chests = player.chests
    data.chest_integral = player.chest_integral
    data.equip_rune = player.equip_rune
    data.unlock_level = player.unlock_level
    data.init_rune_trough = player.init_rune_trough
    data.init_reward_finished = player.init_reward_finished
    data.play_days = player.play_days
    data.play_day_key = player.play_day_key
    data.hasReport = player.hasReport or false
    data.hasReportSeasonRank = player.hasReportSeasonRank or false
    data.lastReportSeasonRankId = player.lastReportSeasonRankId or -1
    data.isBeenHall = player.isBeenHall or false
    data.license_isNew = player.license_isNew or false
    DBManager:savePlayerData(player.userId, GAME_DATA, data, immediate)
end

