function DbUtil:getPlayerData(player)
    DBManager:getPlayerManyData(player.userId, AllKey, function(userId, result)
        local _player = PlayerManager:getPlayerByUserId(userId)
        if not _player then
            return
        end
        local data = result[GAME_DATA]
        _player.isFirstHall = false
        if not data.__first then
            _player.level = ExpConfig:getPlayerInitLv(data.level or 1)
            _player.cur_exp = data.cur_exp or 0
            _player.yaoshi = data.yaoshi or 0
            _player.expDoubleTime = data.expDoubleTime or 0
            _player.privilegeCard = data.privilegeCard or {}
            _player.equip_dress = data.equip_dress or {}
            _player.chest_integral = data.chest_integral or 0
            _player.chests = data.chests or {}
            _player.equip_rune = data.equip_rune or {}
            _player.unlock_level = data.unlock_level or {}
            _player.init_rune_trough = data.init_rune_trough or false
            _player.init_reward_finished = data.init_reward_finished or false
            _player.play_days = data.play_days or 0
            _player.play_day_key = data.play_day_key or 0
            _player.hasReport = data.hasReport or false
            _player.hasReportSeasonRank = data.hasReportSeasonRank or false
            _player.lastReportSeasonRankId = data.lastReportSeasonRankId or -1
            _player.isBeenHall = data.isBeenHall or (_player.level ~= 1 or _player.cur_exp ~= 0)
            _player.license_isNew = data.license_isNew or false
            if _player.expDoubleTime > os.time() then
                Privilege.addPrivilegeTime(_player, 106, _player.expDoubleTime - os.time())
                _player.expDoubleTime = 0
            end
        end
        data = result[REWARD_DATA]
        if not data.__first then
            _player.rewards = data.rewards or {}
        end
        data = result[RUNE_DATA]
        if not data.__first then
            _player.rune = data.rune or {}
            _player.init_exp = data.init_exp or false
        end
        data = result[UPDATE_DATA]
        if not data.__first then
            _player.updateTipsVersion = data.updateTipsVersion or 0
        end
        data = result[CUSTOM_SHOP_DATA]
        if not data.__first then
            _player.custom_goods = data.custom_goods or {}
            ---定制商品增加 GetWay 字段
            for _, group in pairs(_player.custom_goods) do
                for _, _goods in pairs(group) do
                    if #_goods == 3 then
                        local config = CustomShopConfig:getGoodsConfig(_goods[1])
                        if config then
                            _goods[CustomGoodsIndex.GetWay] = config.GetWay
                        end
                    end
                end
            end
        end
        data = result[COMMAND_LIST_DATA]
        if not data.__first then
            _player.command_list = data.command_list or {}
        end
        data = result[TASK_DATA]
        if not data.__first then
            _player.daily_tasks = data.daily_tasks
            _player.task_progresses = data.task_progresses
        end
        data = result[LICENSE_DATA]
        if not data.__first then
            _player.license_season = data.license_season or 0
            _player.license_buy = data.license_buy or 0
            _player.license_exp = data.license_exp or 0
            _player.license_level = data.license_level or 1
            _player.license_week_exp = data.license_week_exp or 0
            _player.refresh_times = data.refresh_times or 1
            _player.license_week = data.license_week or 0
            _player.had_horn = data.had_horn or 0
            _player.free_upgrade_time = data.free_upgrade_time or 0
            _player.get_free_reward = data.get_free_reward or {}
            _player.get_pay_reward = data.get_pay_reward or {}
            _player.exchange_reward = data.exchange_reward or {}
            _player.finish_task = data.finish_task or {}
            _player.show_effect_task = data.show_effect_task or {}
        end
        data = result[DRESS_DATA]
        if not data.__first then
            _player.dress = data.dress or {}
        end
        data = result[TREASURE_CHALLENGE_DATA]
        if not data.__first then
            _player.challenges = data.challenges or {}
            _player.needNewChallengeTip = data.needNewChallengeTip or false
        end
        data = result[BLOCK_SHOP_DATA]
        if not data.__first then
            _player.game_day_key = data.game_day_key or 0
            _player.hall_day_key = data.hall_day_key or 0
            _player.block_goods = data.block_goods or {}
        end
        data = result[FREE_GIFT_DATA]
        if not data.__first then
            _player.free_gift_refresh_time = data.free_gift_refresh_time or DateUtil.getYearDay()
            _player.ticket_num = data.ticket_num or 0
            _player.free_gift = data.free_gift or {}
            _player.challenge_ad = data.challenge_ad or false
        end
        _player:initDBDataFinished()
        ---检查首冲异常逻辑
        data = result["SumRecharge"]
        if not data.__first then
            if tonumber(data.currentId) == 0 then
                local petTab = _player.custom_goods["1"]
                if not petTab or not petTab["3001"] then
                    SumRechargeHelper:resetSumRecharge(_player)
                end
            end
        end
    end)
end

